import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface WeeklyStats {
  day: string;
  reviews: number;
}

interface WidgetData {
  pendingReviews: number;
  averageReviewTime: string;
  weeklyStats: WeeklyStats[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const metaData = response.meta as MetaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: metaData.theme === 'dark' ? '#1A202C' : '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: metaData.primaryColor }}>
              CodeReview Tracker
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Pending Reviews: {widgetData.pendingReviews}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Avg. Review Time: {widgetData.averageReviewTime}
            </Typography>
          </Box>

          <BarChart
            height={140}
            series={[
              {
                data: widgetData.weeklyStats.map(stat => stat.reviews),
                color: metaData.accentColor,
              },
            ]}
            xAxis={[
              {
                data: widgetData.weeklyStats.map(stat => stat.day),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#A0AEC0',
                },
              }
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
